(window.webpackJsonp=window.webpackJsonp||[]).push([[25],{47:function(e,t,o){"use strict";o.r(t);var n=o(0),a=function(e){var t,o,n,a,l,s,r,u,i,p,g=(t=void 0,o="Prometheus",n={},a=new Date(1585042574251),l={},s="post",r="为什么选择prometheus：",u="安装prometheus",i="exporter",p="一些问题",n.type="page",n.internal=t,n.contentType="default",n.isTagPage=!0,n.layout="tag",n.permalink="/tags/prometheus",n.slug="prometheus",n.createdAt=a,n.updatedAt=a,n.posts=[l],n.pagination={hasPrev:!1,hasNext:!1,total:1,current:1,prevLink:"/tags/prometheus/page/2",nextLink:t},n.tag=o,n.assets={},n.attributes=n,n.content=t,l.type=s,l.internal=t,l.contentType="markdown",l.slug=o,l.content=t,l.createdAt=new Date(15619392e5),l.updatedAt=new Date(1584947383838),l.title="Prometheus+Grafana监控实践",l.date="2019-07-01",l.layout=s,l.tags=o,l.markdownHeadings=[{text:"什么是Prometheus",slug:"什么是prometheus",level:4},{text:r,slug:r,level:4},{text:u,slug:u,level:4},{text:"此时，prometheus 服务已在后台运行，注意暴露的端口号 9090（address=0.0.0.0:9090），可以直接在浏览器打开 ip:9090 查看简易控制台，此控制台可以做调试使用，需要更强大、美观的数据展示官方建议使用 Grafana.",slug:"此时，prometheus-服务已在后台运行，注意暴露的端口号-9090（address0-0-0-09090），可以直接在浏览器打开-ip9090-查看简易控制台，此控制台可以做调试使用，需要更强大、美观的数据展示官方建议使用-grafana-",level:5},{text:"安装 grafana",slug:"安装-grafana",level:4},{text:i,slug:i,level:4},{text:"安装 prometheus",slug:"安装-prometheus",level:4},{text:"启动",slug:"启动",level:5},{text:"Prometheus配置的热加载",slug:"prometheus配置的热加载",level:4},{text:"告警服务 Alertmanager",slug:"告警服务-alertmanager",level:4},{text:p,slug:p,level:4}],l.excerpt='<h4 id="什么是prometheus">什么是Prometheus</h4>\n<blockquote>\n<p>Prometheus 是由 SoundCloud 开源监控告警解决方案，从 2012 年开始编写代码，再到 2015 年 github 上开源以来，已经吸引了 9k+ 关注，以及很多大公司的使用；2016 年 Prometheus 成为继 k8s 后，第二名 CNCF(Cloud Native Computing Foundation) 成员。</p>\n</blockquote>\n<p>作为新一代开源解决方案，很多理念与 Google SRE 运维之道不谋而合。</p>\n<h4 id="为什么选择prometheus：">为什么选择prometheus：</h4>\n<ul>\n<li>Prometheus 是按照 Google SRE 运维之道的理念构建的，具有实用性和前瞻性。</li>\n<li>Prometheus 社区非常活跃，基本稳定在 1个月1个版本的迭代速度，从 2016 年 v1.01 开始接触使用以来，到目前发布的 v1.8.2 以及最新最新的 v2.1 ，你会发现 Prometheus 一直在进步、在优化。</li>\n<li>Go 语言开发，性能不错，安装部署简单，多平台部署兼容性好。</li>\n<li>丰富的数据收集客户端，官方提供了各种常用 exporter。</li>\n<li>丰富强大的查询能力,内置更强大的统计函数。</li>\n<li>Prometheus 属于一站式监控告警平台，依赖少，功能齐全。</li>\n<li>Prometheus支持对云或容器的监控，其他监控系统主要对主机监控。</li>\n</ul>\n',l.permalink="/blog/Prometheus",l.assets={},l.attributes=l,n),h=e.options.beforeCreate||[];e.options.beforeCreate=[function(){this.$page=g}].concat(h);["layout","transition"].forEach((function(t){var o=e.options.PageComponent;o&&(e.options[t]=o[t]),void 0===e.options[t]&&(e.options[t]=g[t])})),g.slug&&(e.options.name="page-wrapper-"+g.slug.replace(/[^0-9a-z\-]/gi,"-"))},l=Object(n.a)({},(function(){var e=this.$createElement;return(this._self._c||e)("layout-manager")}),[],!1,null,null,null);"function"==typeof a&&a(l);t.default=l.exports}}]);